const arr = [1, 2, 3];
const obj = { id: 1 };
const str = 'hello';

//  BAD: Built-in Constructors (unnecessary, slow, confusing)
const arr2 = new Array(1, 2, 3);
const obj2 = new Object();
obj2.id = 1;

//  DANGER ZONE: Wrapper Objects
const str2 = new String('hello');
